import{_ as a,o as l,c as d,b4 as i}from"./chunks/framework.tGVskLkL.js";const b=JSON.parse('{"title":"htop 完整使用指南","description":"","frontmatter":{},"headers":[],"relativePath":"linux/htop.md","filePath":"linux/htop.md"}'),t={name:"linux/htop.md"};function o(r,e,c,h,n,s){return l(),d("div",null,e[0]||(e[0]=[i('<h1 id="htop-完整使用指南" tabindex="-1">htop 完整使用指南 <a class="header-anchor" href="#htop-完整使用指南" aria-label="Permalink to “htop 完整使用指南”">​</a></h1><p>适用于 Linux / Mac，查看进程、CPU、内存、排查性能神器</p><h2 id="一、顶部信息说明" tabindex="-1">一、顶部信息说明 <a class="header-anchor" href="#一、顶部信息说明" aria-label="Permalink to “一、顶部信息说明”">​</a></h2><h3 id="_1-顶部状态栏" tabindex="-1">1. 顶部状态栏 <a class="header-anchor" href="#_1-顶部状态栏" aria-label="Permalink to “1. 顶部状态栏”">​</a></h3><ul><li>CPU 核心条：每个核心使用率 <ul><li>绿：用户进程</li><li>红：内核进程</li><li>蓝：低优先级进程</li><li>黄：IO 等待</li></ul></li><li>Mem：物理内存使用</li><li>Swp：交换分区（虚拟内存）</li><li>Load average：1/5/15 分钟系统负载</li><li>Uptime：系统运行时间</li></ul><h3 id="_2-进程列含义" tabindex="-1">2. 进程列含义 <a class="header-anchor" href="#_2-进程列含义" aria-label="Permalink to “2. 进程列含义”">​</a></h3><table tabindex="0"><thead><tr><th>列名</th><th>含义</th></tr></thead><tbody><tr><td>PID</td><td>进程 ID</td></tr><tr><td>USER</td><td>运行用户</td></tr><tr><td>PRI</td><td>内核优先级（越小越高）</td></tr><tr><td>NI</td><td>用户可设置优先级（-20~19）</td></tr><tr><td>VIRT</td><td>虚拟内存（参考）</td></tr><tr><td>RES</td><td>真实物理内存（重点看）</td></tr><tr><td>SHR</td><td>共享内存</td></tr><tr><td>S</td><td>进程状态 R运行 S休眠 D等待IO Z僵尸</td></tr><tr><td>CPU%</td><td>CPU 使用率</td></tr><tr><td>MEM%</td><td>内存使用率</td></tr></tbody></table><hr><h2 id="二、最常用快捷键" tabindex="-1">二、最常用快捷键 <a class="header-anchor" href="#二、最常用快捷键" aria-label="Permalink to “二、最常用快捷键”">​</a></h2><h3 id="显示控制" tabindex="-1">显示控制 <a class="header-anchor" href="#显示控制" aria-label="Permalink to “显示控制”">​</a></h3><ul><li><code>h</code>：帮助</li><li><code>H</code>：显示/隐藏线程（解决 Node 多 PID）</li><li><code>t</code>：树状显示进程</li><li><code>F2</code>：设置</li></ul><h3 id="排序" tabindex="-1">排序 <a class="header-anchor" href="#排序" aria-label="Permalink to “排序”">​</a></h3><ul><li><code>P</code>：按 CPU 排序</li><li><code>M</code>：按内存排序</li><li><code>T</code>：按运行时间排序</li></ul><h3 id="操作" tabindex="-1">操作 <a class="header-anchor" href="#操作" aria-label="Permalink to “操作”">​</a></h3><ul><li><code>/</code> 或 <code>F3</code>：搜索进程</li><li><code>u</code>：筛选用户</li><li><code>k</code> 或 <code>F9</code>：杀死进程</li><li><code>q</code>：退出</li></ul><hr><h2 id="三、日常高频用法" tabindex="-1">三、日常高频用法 <a class="header-anchor" href="#三、日常高频用法" aria-label="Permalink to “三、日常高频用法”">​</a></h2><h3 id="_1-只看主进程-不看多线程" tabindex="-1">1. 只看主进程（不看多线程） <a class="header-anchor" href="#_1-只看主进程-不看多线程" aria-label="Permalink to “1. 只看主进程（不看多线程）”">​</a></h3><p>按 <code>H</code></p><h3 id="_2-找最耗-cpu-内存-的进程" tabindex="-1">2. 找最耗 CPU/内存 的进程 <a class="header-anchor" href="#_2-找最耗-cpu-内存-的进程" aria-label="Permalink to “2. 找最耗 CPU/内存 的进程”">​</a></h3><ul><li>CPU：<code>P</code></li><li>内存：<code>M</code></li></ul><h3 id="_3-杀死进程" tabindex="-1">3. 杀死进程 <a class="header-anchor" href="#_3-杀死进程" aria-label="Permalink to “3. 杀死进程”">​</a></h3><p>选中 → <code>F9</code> →</p><ul><li>15 SIGTERM（正常关闭）</li><li>9 SIGKILL（强制杀死）</li></ul><h3 id="_4-查看进程树" tabindex="-1">4. 查看进程树 <a class="header-anchor" href="#_4-查看进程树" aria-label="Permalink to “4. 查看进程树”">​</a></h3><p>按 <code>t</code></p><h3 id="_5-搜索某个服务" tabindex="-1">5. 搜索某个服务 <a class="header-anchor" href="#_5-搜索某个服务" aria-label="Permalink to “5. 搜索某个服务”">​</a></h3><p>按 <code>/</code> 输入关键词，如 <code>node</code> <code>nginx</code></p><hr><h2 id="四、排查场景速查" tabindex="-1">四、排查场景速查 <a class="header-anchor" href="#四、排查场景速查" aria-label="Permalink to “四、排查场景速查”">​</a></h2><ol><li>CPU 高 <ul><li>按 <code>P</code> → 找到占用高的进程</li></ul></li><li>内存高 <ul><li>按 <code>M</code> → 看 RES</li></ul></li><li>系统卡顿、IO 高 <ul><li>看 CPU 条黄色（iowait）</li></ul></li><li>Node.js 出现多个 PID <ul><li>按 <code>H</code> 隐藏线程，正常现象</li></ul></li></ol><hr><h2 id="五、极简记忆" tabindex="-1">五、极简记忆 <a class="header-anchor" href="#五、极简记忆" aria-label="Permalink to “五、极简记忆”">​</a></h2><ul><li><code>h</code> 帮助</li><li><code>H</code> 隐藏线程</li><li><code>P</code> CPU 排序</li><li><code>M</code> 内存排序</li><li><code>F9</code> 杀进程</li><li><code>q</code> 退出</li></ul>',34)]))}const u=a(t,[["render",o]]);export{b as __pageData,u as default};
